#include<bits/stdc++.h>
using namespace std;

const int N = 1e4 + 5;
const int K = 105;

int n, m, k;
struct Edge {
    int v, a;
};
vector<Edge> e[N];

int dis[N][K]; 
bool vis[N][K]; 

void Dijkstra() {
    memset(dis, 0x3f, sizeof dis);
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;
    dis[1][0] = 0;
    pq.push({0, 1 * 100 + 0});
    while (!pq.empty()) {
        auto [d, st] = pq.top(); pq.pop();
        int u = st / 100, j = st % 100;
        if (vis[u][j]) continue;
        vis[u][j] = true;
        for (auto [v, a] : e[u]) {
            int wait = 0;
            if (d < a) {
                wait = (a - d + k - 1) / k * k;
            }
            int new_t = d + wait + 1;
            int new_j = (j + 1) % k;
            if (new_t < dis[v][new_j]) {
                dis[v][new_j] = new_t;
                pq.push({new_t, v * 100 + new_j});
            }
        }
    }
}

int main() {
    cin.tie(0)->sync_with_stdio(0);
    cin >> n >> m >> k;
    for (int i=1; i<=m; i++) {
        int u, v, a;
        cin >> u >> v >> a;
        e[u].push_back({v, a});
    }
    Dijkstra();
    if (dis[n][0] >= 0x3f3f3f3f) cout << -1 << endl;
    else cout << dis[n][0] << endl;
    return 0;
}
